// ethers.js: new ethers.Contract(address, abi, signer)
const contract = getContract({ address: '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48', abi, client: { public: publicClient, wallet: walletClient } })

// Return type is bigint — no BigNumber, no casting
const balance: bigint = await contract.read.balanceOf([account.address])

import { ethers } from "ethers";
import axios from "axios";

async function pinAndMint(metadata: object, contractAddress: string) {
  const { data } = await axios.post(
    "https://api.pinata.cloud/pinning/pinJSONToIPFS",
    metadata,
    { headers: { Authorization: `Bearer ${process.env.PINATA_JWT}` } }
  );
  const tokenURI = `ipfs://${data.IpfsHash}`;

  const provider = new ethers.BrowserProvider(window.ethereum);
  const signer = await provider.getSigner();
  const nft = new ethers.Contract(
    contractAddress,
    ["function mint(address to, string uri) returns (uint256)"],
    signer
  );

  const tx = await nft.mint(await signer.getAddress(), tokenURI);
  return tx.wait();
}

import { Interface, Contract, JsonRpcProvider } from 'ethers';

const abi = [
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
];

// Standalone Interface — no provider needed
const iface = new Interface(abi);
const calldata = iface.encodeFunctionData('transfer', [
  '0xRecipient...',
  1000n,
]);
console.log(calldata); // 0xa9059cbb...

// Decode raw result bytes
const rawResult = '0x0000...0001';
const [success] = iface.decodeFunctionResult('transfer', rawResult);

// Full contract instance — encoding/decoding is automatic
const provider = new JsonRpcProvider(process.env.RPC_URL);
const token = new Contract('0xToken...', abi, provider);
const balance = await token.balanceOf('0xOwner...');

